from collections import deque

def main():
    def topological_sort_bfs_kahn(graph):
        V = len(graph)
        indegree = [0] * V
        topo_order = []
        for u in range(V):
            for v in graph[u]:
                indegree[v] += 1
        queue = deque([i for i in range(V) if indegree[i] == 0])
        while queue:
            u = queue.popleft()
            topo_order.append(u)
            for v in graph[u]:
                indegree[v] -= 1
                if indegree[v] == 0:
                    queue.append(v)
        if len(topo_order) == V:
            return topo_order
        else:
            raise ValueError('Graph has at least one cycle')

    graph = [[1, 2], [3], [3], []]

    def topological_sort_dfs(graph):

        def dfs(v):
            visited[v] = True
            for neighbor in graph[v]:
